typedef struct record {
    int value;
} record;

typedef struct knode {
    int location;
    int indices[DEFAULT_ORDER + 1];
    int keys[DEFAULT_ORDER + 1];
    uchar is_leaf;
    int num_keys;
} knode;

__kernel void findK(__private long maxheight,
                    __global knode *knodes,
                    __private long knodes_elem,
                    __global record *records,
                    __global long *currKnode,
                    __global long *offset,
                    __global int *keys,
                    __global record *ans) {
    const int bid = get_group_id(0);
    const int thid = get_local_id(0);

    for (long i = 0; i < maxheight; i++) {
        long curr = currKnode[bid];
        long off = offset[bid];

        if ((knodes[curr].keys[thid] <= keys[bid]) &&
            (knodes[curr].keys[thid + 1] > keys[bid])) {
            if (knodes[off].indices[thid] < knodes_elem) {
                offset[bid] = (long)knodes[off].indices[thid];
            }
        }

        barrier(CLK_GLOBAL_MEM_FENCE);

        if (thid == 0) {
            currKnode[bid] = offset[bid];
        }

        barrier(CLK_GLOBAL_MEM_FENCE);
    }

    long curr = currKnode[bid];
    if (knodes[curr].keys[thid] == keys[bid]) {
        ans[bid].value = records[knodes[curr].indices[thid]].value;
    }
}

