				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;
				p_in2_sqr_sub2[col * common.conv_rows + row] = temp2;
				temp2 = temp2 - (p_in2_sub2[col * common.conv_rows + row] / (fp)common.in_elem);
				if (temp2 < 0.0f) temp2 = 0.0f;
				temp2 = sqrt(temp2);
				temp2 = denomT * temp2;
				p_conv[col * common.conv_rows + row] = p_conv[col * common.conv_rows + row] / temp2;
			}
		}

		cent = common.sSize + common.tSize + 1;
		pointer = frame_no - 1 + point_no * common.no_frames;
		tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
		tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

		for (ei_new = 0; ei_new < common.tMask_elem; ei_new++) {
			p_tMask[ei_new] = 0.0f;
		}
		p_tMask[tMask_col * common.tMask_rows + tMask_row] = 1.0f;

		for (col = 1; col <= common.mask_conv_cols; col++) {
			j = col + common.mask_conv_joffset;
			jp1 = j + 1;
			if (common.mask_cols < jp1) ja1 = jp1 - common.mask_cols;
			else ja1 = 1;
			if (common.tMask_cols < j) ja2 = common.tMask_cols;
			else ja2 = j;

			for (row = 1; row <= common.mask_conv_rows; row++) {
				i = row + common.mask_conv_ioffset;
				ip1 = i + 1;
				if (common.mask_rows < ip1) ia1 = ip1 - common.mask_rows;
				else ia1 = 1;
				if (common.tMask_rows < i) ia2 = common.tMask_rows;
				else ia2 = i;

				s = 0.0f;
				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						s += p_tMask[common.tMask_rows * (ja - 1) + ia - 1] * 1.0f;
					}
				}
				p_mask_conv[(col - 1) * common.conv_rows + (row - 1)] =
					p_conv[(col - 1) * common.conv_rows + (row - 1)] * s;
			}
		}

		fin_max_val = 0.0f;
		fin_max_coo = 0;
		for (i = 0; i < common.mask_conv_elem; i++) {
			if (p_mask_conv[i] > fin_max_val) {
				fin_max_val = p_mask_conv[i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
		if ((fin_max_coo + 1) % common.mask_conv_rows == 0) {
			largest_row = common.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
		offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);

		pointer = point_no * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
		d_tColLoc[pointer] = d_Col[point_no] + offset_col;
	}

	if (frame_no != 0 && (frame_no % 10) == 0) {
		loc_pointer = point_no * common.no_frames + frame_no;
		d_Row[point_no] = d_tRowLoc[loc_pointer];
		d_Col[point_no] = d_tColLoc[loc_pointer];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				d_T[col * common.in_rows + row] =
					common.alpha * d_T[col * common.in_rows + row] +
					(1.0f - common.alpha) * d_frame[ori_pointer];
			}
		}
	}
}

#define fp float

typedef struct params_common{

	int common_change_mem;
	int common_mem;
	int unique_mem;

	int frames_processed;

	int sSize;
	int tSize;
	int maxMove;
	fp alpha;

	int no_frames;
	int frame_rows;
	int frame_cols;
	int frame_elem;
	int frame_mem;

	int endoPoints;
	int endo_mem;

	int epiPoints;
	int epi_mem;

	int allPoints;

	int in_rows;
	int in_cols;
	int in_elem;
	int in_mem;

	int in_pointer_mem;

	int in2_rows;
	int in2_cols;
	int in2_elem;
	int in2_mem;

	int conv_rows;
	int conv_cols;
	int conv_elem;
	int conv_mem;
	int ioffset;
	int joffset;

	int in2_pad_add_rows;
	int in2_pad_add_cols;
	int in2_pad_cumv_rows;
	int in2_pad_cumv_cols;
	int in2_pad_cumv_elem;
	int in2_pad_cumv_mem;

	int in2_pad_cumv_sel_rows;
	int in2_pad_cumv_sel_cols;
	int in2_pad_cumv_sel_elem;
	int in2_pad_cumv_sel_mem;
	int in2_pad_cumv_sel_rowlow;
	int in2_pad_cumv_sel_rowhig;
	int in2_pad_cumv_sel_collow;
	int in2_pad_cumv_sel_colhig;

	int in2_pad_cumv_sel2_rowlow;
	int in2_pad_cumv_sel2_rowhig;
	int in2_pad_cumv_sel2_collow;
	int in2_pad_cumv_sel2_colhig;
	int in2_sub_cumh_rows;
	int in2_sub_cumh_cols;
	int in2_sub_cumh_elem;
	int in2_sub_cumh_mem;

	int in2_sub_cumh_sel_rows;
	int in2_sub_cumh_sel_cols;
	int in2_sub_cumh_sel_elem;
	int in2_sub_cumh_sel_mem;
	int in2_sub_cumh_sel_rowlow;
	int in2_sub_cumh_sel_rowhig;
	int in2_sub_cumh_sel_collow;
	int in2_sub_cumh_sel_colhig;

	int in2_sub_cumh_sel2_rowlow;
	int in2_sub_cumh_sel2_rowhig;
	int in2_sub_cumh_sel2_collow;
	int in2_sub_cumh_sel2_colhig;
	int in2_sub2_rows;
	int in2_sub2_cols;
	int in2_sub2_elem;
	int in2_sub2_mem;

	int in2_sqr_rows;
	int in2_sqr_cols;
	int in2_sqr_elem;
	int in2_sqr_mem;

	int in2_sqr_sub2_rows;
	int in2_sqr_sub2_cols;
	int in2_sqr_sub2_elem;
	int in2_sqr_sub2_mem;

	int in_sqr_rows;
	int in_sqr_cols;
	int in_sqr_elem;
	int in_sqr_mem;

	int tMask_rows;
	int tMask_cols;
	int tMask_elem;
	int tMask_mem;

	int mask_rows;
	int mask_cols;
	int mask_elem;
	int mask_mem;

	int mask_conv_rows;
	int mask_conv_cols;
	int mask_conv_elem;
	int mask_conv_mem;
	int mask_conv_ioffset;
	int mask_conv_joffset;

} params_common;

__kernel void kernel_gpu_opencl(
	params_common common,
	int frame_no,
	__global fp* d_frame,
	__global int* d_Row,
	__global int* d_Col,
	__global int* d_tRowLoc,
	__global int* d_tColLoc,
	__global fp* d_T,
	__global fp* d_in2,
	__global fp* d_in2_sqr,
	__global fp* d_in_mod,
	__global fp* d_in_sqr,
	__global fp* d_conv,
	__global fp* d_in2_pad_cumv,
	__global fp* d_in2_sub_cumh,
	__global fp* d_in2_sub2,
	__global fp* d_in2_sqr_sub2,
	__global fp* d_tMask,
	__global fp* d_mask_conv)
{
	int tx = (int)get_global_id(0);
	if(tx >= common.allPoints) return;

	int in_pointer = tx * common.in_elem;
	int in2_pointer = tx * common.in2_elem;
	int in2_sqr_pointer = tx * common.in2_sqr_elem;
	int in_mod_pointer = tx * common.in_elem;
	int in_sqr_pointer = tx * common.in_sqr_elem;
	int conv_pointer = tx * common.conv_elem;
	int in2_pad_pointer = tx * common.in2_pad_cumv_elem;
	int in2_sub_pointer = tx * common.in2_sub_cumh_elem;
	int in2_sub2_pointer = tx * common.in2_sub2_elem;
	int in2_sqr_sub2_pointer = tx * common.in2_sqr_sub2_elem;
	int tMask_pointer = tx * common.tMask_elem;
	int mask_conv_pointer = tx * common.mask_conv_elem;

	int ei_new;
	__global fp* in = &d_T[in_pointer];
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic, jc;
	int jp1, ja1, ja2;
	int ip1, ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i, j;
	int row, col;
	int ori_row, ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int cent;
	int tMask_row;
	int tMask_col;
	fp fin_max_val = 0;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp in_final_sum;
	fp in_sqr_final_sum;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	fp denomT;
	int pointer;
	int ori_pointer;
	int loc_pointer;

	if(frame_no == 0){
		pointer = tx * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[tx];
		d_tColLoc[pointer] = d_Col[tx];

		for(col = 0; col < common.in_cols; col++){
			for(row = 0; row < common.in_rows; row++){
				ori_row = d_Row[tx] - 25 + row - 1;
				ori_col = d_Col[tx] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				in[col * common.in_rows + row] = d_frame[ori_pointer];
			}
		}
	}

	if(frame_no != 0){

		in2_rowlow = d_Row[tx] - common.sSize;
		in2_collow = d_Col[tx] - common.sSize;

		for(col = 0; col < common.in2_cols; col++){
			for(row = 0; row < common.in2_rows; row++){
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = d_frame[ori_col * common.frame_rows + ori_row];
				d_in2[in2_pointer + col * common.in2_rows + row] = temp;
				d_in2_sqr[in2_sqr_pointer + col * common.in2_rows + row] = temp * temp;
			}
		}

		for(col = 0; col < common.in_cols; col++){
			for(row = 0; row < common.in_rows; row++){
				rot_row = (common.in_rows - 1) - row;
				rot_col = (common.in_rows - 1) - col;
				pointer = rot_col * common.in_rows + rot_row;
				temp = in[pointer];
				d_in_mod[in_mod_pointer + col * common.in_rows + row] = temp;
				d_in_sqr[in_sqr_pointer + pointer] = temp * temp;
			}
		}

		in_final_sum = 0;
		for(i = 0; i < common.in_elem; i++){
			in_final_sum += in[i];
		}

		in_sqr_final_sum = 0;
		for(i = 0; i < common.in_elem; i++){
			in_sqr_final_sum += d_in_sqr[in_sqr_pointer + i];
		}

		mean = in_final_sum / (fp)common.in_elem;
		mean_sqr = mean * mean;
		variance = (in_sqr_final_sum / (fp)common.in_elem) - mean_sqr;
		deviation = sqrt(variance);
		denomT = sqrt((fp)(common.in_elem - 1)) * deviation;

		for(col = 1; col <= common.conv_cols; col++){
			j = col + common.joffset;
			jp1 = j + 1;
			ja1 = (common.in2_cols < jp1) ? (jp1 - common.in2_cols) : 1;
			ja2 = (common.in_cols < j) ? common.in_cols : j;

			for(row = 1; row <= common.conv_rows; row++){
				i = row + common.ioffset;
				ip1 = i + 1;
				ia1 = (common.in2_rows < ip1) ? (ip1 - common.in2_rows) : 1;
				ia2 = (common.in_rows < i) ? common.in_rows : i;

				s = 0;
				for(ja = ja1; ja <= ja2; ja++){
					jb = jp1 - ja;
					for(ia = ia1; ia <= ia2; ia++){
						ib = ip1 - ia;
						s += d_in_mod[in_mod_pointer + common.in_rows * (ja - 1) + ia - 1] *
							 d_in2[in2_pointer + common.in2_rows * (jb - 1) + ib - 1];
					}
				}
				d_conv[conv_pointer + (col - 1) * common.conv_rows + (row - 1)] = s;
			}
		}

		for(col = 0; col < common.in2_pad_cumv_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_rows; row++){
				if(row > (common.in2_pad_add_rows - 1) &&
				   row < (common.in2_pad_add_rows + common.in2_rows) &&
				   col > (common.in2_pad_add_cols - 1) &&
				   col < (common.in2_pad_add_cols + common.in2_cols)){
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					d_in2_pad_cumv[in2_pad_pointer + col * common.in2_pad_cumv_rows + row] =
						d_in2[in2_pointer + ori_col * common.in2_rows + ori_row];
				}else{
					d_in2_pad_cumv[in2_pad_pointer + col * common.in2_pad_cumv_rows + row] = 0;
				}
			}
		}

		for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++){
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0;
			for(position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++){
				d_in2_pad_cumv[in2_pad_pointer + position] += sum;
				sum = d_in2_pad_cumv[in2_pad_pointer + position];
			}
		}

		for(col = 0; col < common.in2_pad_cumv_sel_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_sel_rows; row++){
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = d_in2_pad_cumv[in2_pad_pointer + ori_col * common.in2_pad_cumv_rows + ori_row];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = d_in2_pad_cumv[in2_pad_pointer + ori_col * common.in2_pad_cumv_rows + ori_row];

				d_in2_sub_cumh[in2_sub_pointer + col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0;
			for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows){
				d_in2_sub_cumh[in2_sub_pointer + position] += sum;
				sum = d_in2_sub_cumh[in2_sub_pointer + position];
			}
		}

		for(col = 0; col < common.in2_sub2_cols; col++){
			for(row = 0; row < common.in2_sub2_rows; row++){
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = d_in2_sub_cumh[in2_sub_pointer + ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = d_in2_sub_cumh[in2_sub_pointer + ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;
				d_in2_sub2[in2_sub2_pointer + col * common.in2_sub2_rows + row] = temp2 * temp2;

				d_conv[conv_pointer + col * common.in2_sub2_rows + row] -= temp2 * in_final_sum / (fp)common.in_elem;
			}
		}

		for(col = 0; col < common.in2_pad_cumv_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_rows; row++){
				if(row > (common.in2_pad_add_rows - 1) &&
				   row < (common.in2_pad_add_rows + common.in2_rows) &&
				   col > (common.in2_pad_add_cols - 1) &&
				   col < (common.in2_pad_add_cols + common.in2_cols)){
					ori_row = row - common.in2_pad_add_rows;
					ori_col = col - common.in2_pad_add_cols;
					d_in2_pad_cumv[in2_pad_pointer + col * common.in2_pad_cumv_rows + row] =
						d_in2_sqr[in2_sqr_pointer + ori_col * common.in2_rows + ori_row];
				}else{
					d_in2_pad_cumv[in2_pad_pointer + col * common.in2_pad_cumv_rows + row] = 0;
				}
			}
		}

		for(ei_new = 0; ei_new < common.in2_pad_cumv_cols; ei_new++){
			pos_ori = ei_new * common.in2_pad_cumv_rows;
			sum = 0;
			for(position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++){
				d_in2_pad_cumv[in2_pad_pointer + position] += sum;
				sum = d_in2_pad_cumv[in2_pad_pointer + position];
			}
		}

		for(col = 0; col < common.in2_pad_cumv_sel_cols; col++){
			for(row = 0; row < common.in2_pad_cumv_sel_rows; row++){
				ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel_collow - 1;
				temp = d_in2_pad_cumv[in2_pad_pointer + ori_col * common.in2_pad_cumv_rows + ori_row];

				ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
				temp2 = d_in2_pad_cumv[in2_pad_pointer + ori_col * common.in2_pad_cumv_rows + ori_row];

				d_in2_sub_cumh[in2_sub_pointer + col * common.in2_sub_cumh_rows + row] = temp - temp2;
			}
		}

		for(ei_new = 0; ei_new < common.in2_sub_cumh_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0;
			for(position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows){
				d_in2_sub_cumh[in2_sub_pointer + position] += sum;
				sum = d_in2_sub_cumh[in2_sub_pointer + position];
			}
		}

		for(col = 0; col < common.conv_cols; col++){
			for(row = 0; row < common.conv_rows; row++){
				ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel_collow - 1;
				temp = d_in2_sub_cumh[in2_sub_pointer + ori_col * common.in2_sub_cumh_rows + ori_row];

				ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
				temp2 = d_in2_sub_cumh[in2_sub_pointer + ori_col * common.in2_sub_cumh_rows + ori_row];

				temp2 = temp - temp2;
				d_in2_sqr_sub2[in2_sqr_sub2_pointer + col * common.conv_rows + row] = temp2;
				temp2 = temp2 - (d_in2_sub2[in2_sub2_pointer + col * common.conv_rows + row] / (fp)common.in_elem);

				if(temp2 < 0) temp2 = 0;
				temp2 = sqrt(temp2);
				temp2 = denomT * temp2;

				d_conv[conv_pointer + col * common.conv_rows + row] =
					d_conv[conv_pointer + col * common.conv_rows + row] / temp2;
			}
		}

		cent = common.sSize + common.tSize + 1;
		pointer = frame_no - 1 + tx * common.no_frames;
		tMask_row = cent + d_tRowLoc[pointer] - d_Row[tx] - 1;
		tMask_col = cent + d_tColLoc[pointer] - d_Col[tx] - 1;

		for(ei_new = 0; ei_new < common.tMask_elem; ei_new++){
			d_tMask[tMask_pointer + ei_new] = 0;
		}
		d_tMask[tMask_pointer + tMask_col * common.tMask_rows + tMask_row] = 1;

		for(col = 1; col <= common.mask_conv_cols; col++){
			j = col + common.mask_conv_joffset;
			jp1 = j + 1;
			ja1 = (common.mask_cols < jp1) ? (jp1 - common.mask_cols) : 1;
			ja2 = (common.tMask_cols < j) ? common.tMask_cols : j;

			for(row = 1; row <= common.mask_conv_rows; row++){
				i = row + common.mask_conv_ioffset;
				ip1 = i + 1;
				ia1 = (common.mask_rows < ip1) ? (ip1 - common.mask_rows) : 1;
				ia2 = (common.tMask_rows < i) ? common.tMask_rows : i;

				s = 0;
				for(ja = ja1; ja <= ja2; ja++){
					jb = jp1 - ja;
					for(ia = ia1; ia <= ia2; ia++){
						ib = ip1 - ia;
						(void)jb;
						(void)ib;
						s += d_tMask[tMask_pointer + common.tMask_rows * (ja - 1) + ia - 1];
					}
				}

				d_mask_conv[mask_conv_pointer + (col - 1) * common.conv_rows + (row - 1)] =
					d_conv[conv_pointer + (col - 1) * common.conv_rows + (row - 1)] * s;
			}
		}

		fin_max_val = 0;
		fin_max_coo = 0;
		for(i = 0; i < common.mask_conv_elem; i++){
			if(d_mask_conv[mask_conv_pointer + i] > fin_max_val){
				fin_max_val = d_mask_conv[mask_conv_pointer + i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
		if((fin_max_coo + 1) % common.mask_conv_rows == 0){
			largest_row = common.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
		offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);

		pointer = tx * common.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[tx] + offset_row;
		d_tColLoc[pointer] = d_Col[tx] + offset_col;
	}

	if(frame_no != 0 && (frame_no % 10) == 0){
		loc_pointer = tx * common.no_frames + frame_no;
		d_Row[tx] = d_tRowLoc[loc_pointer];
		d_Col[tx] = d_tColLoc[loc_pointer];

		for(col = 0; col < common.in_cols; col++){
			for(row = 0; row < common.in_rows; row++){
				ori_row = d_Row[tx] - 25 + row - 1;
				ori_col = d_Col[tx] - 25 + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;

				in[col * common.in_rows + row] =
					common.alpha * in[col * common.in_rows + row] +
					(1.0f - common.alpha) * d_frame[ori_pointer];
			}
		}
	}
}

