__kernel void kernel_gpu_opencl(
	params_common public,
	int frame_no,
	__global fp* d_frame,
	__global int* d_Row,
	__global int* d_Col,
	__global int* d_tRowLoc,
	__global int* d_tColLoc,
	__global fp* d_T,
	__global fp* d_in2,
	__global fp* d_in2_sqr,
	__global fp* d_in_mod,
	__global fp* d_in_sqr,
	__global fp* d_conv,
	__global fp* d_in2_pad_cumv,
	__global fp* d_in2_sub_cumh,
	__global fp* d_in2_sub2,
	__global fp* d_in2_sqr_sub2,
	__global fp* d_tMask,
	__global fp* d_mask_conv)
{
	int point_no = get_global_id(0);
	if (point_no >= public.allPoints) return;

	int ei_new;
	__global fp* in_ptr;
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i;
	int j;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int cent;
	int tMask_row;
	int tMask_col;
	fp fin_max_val = 0.0f;
	int fin_max_coo = 0;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp in_final_sum;
	fp in_sqr_final_sum;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	fp denomT;
	int pointer;
	int ori_pointer;
	int loc_pointer;

	int in_pointer = point_no * public.in_elem;
	int in2_offset = point_no * public.in2_elem;
	int in2s_offset = point_no * public.in2_sqr_elem;
	int in_mod_offset = point_no * public.in_elem;
	int in_sqr_offset = point_no * public.in_sqr_elem;
	int conv_offset = point_no * public.conv_elem;
	int in2_pad_offset = point_no * public.in2_pad_cumv_elem;
	int in2_sub_offset = point_no * public.in2_sub_cumh_elem;
	int in2_sub2_offset = point_no * public.in2_sub2_elem;
	int in2_sqr_sub2_offset = point_no * public.in2_sqr_sub2_elem;
	int tmask_offset = point_no * public.tMask_elem;
	int maskconv_offset = point_no * public.mask_conv_elem;

	__global fp* p_in2 = d_in2 + in2_offset;
	__global fp* p_in2_sqr = d_in2_sqr + in2s_offset;
	__global fp* p_in_mod = d_in_mod + in_mod_offset;
	__global fp* p_in_sqr = d_in_sqr + in_sqr_offset;
	__global fp* p_conv = d_conv + conv_offset;
	__global fp* p_in2_pad = d_in2_pad_cumv + in2_pad_offset;
	__global fp* p_in2_sub = d_in2_sub_cumh + in2_sub_offset;
	__global fp* p_in2_sub2 = d_in2_sub2 + in2_sub2_offset;
	__global fp* p_in2_sqr_sub2 = d_in2_sqr_sub2 + in2_sqr_sub2_offset;
	__global fp* p_tmask = d_tMask + tmask_offset;
	__global fp* p_mask_conv = d_mask_conv + maskconv_offset;

	if(frame_no == 0){
		pointer = point_no*public.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no];
		d_tColLoc[pointer] = d_Col[point_no];

		in_ptr = d_T + in_pointer;

		for(col=0; col<public.in_cols; col++){
			for(row=0; row<public.in_rows; row++){
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				ori_pointer = ori_col*public.frame_rows + ori_row;
				in_ptr[col*public.in_rows + row] = d_frame[ori_pointer];
			}
		}
	}

	if(frame_no != 0){

		in2_rowlow = d_Row[point_no] - public.sSize;
		in2_collow = d_Col[point_no] - public.sSize;

		for(col=0; col<public.in2_cols; col++){
			for(row=0; row<public.in2_rows; row++){
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				temp = d_frame[ori_col*public.frame_rows + ori_row];
				p_in2[col*public.in2_rows + row] = temp;
				p_in2_sqr[col*public.in2_rows + row] = temp*temp;
			}
		}

		in_ptr = d_T + in_pointer;

		for(col=0; col<public.in_cols; col++){
			for(row=0; row<public.in_rows; row++){
				rot_row = (public.in_rows-1) - row;
				rot_col = (public.in_rows-1) - col;
				pointer = rot_col*public.in_rows + rot_row;
				temp = in_ptr[pointer];
				p_in_mod[col*public.in_rows + row] = temp;
				p_in_sqr[pointer] = temp*temp;
			}
		}

		in_final_sum = 0.0f;
		for(i = 0; i < public.in_elem; i++){
			in_final_sum += in_ptr[i];
		}

		in_sqr_final_sum = 0.0f;
		for(i = 0; i < public.in_elem; i++){
			in_sqr_final_sum += p_in_sqr[i];
		}

		mean = in_final_sum / (fp)public.in_elem;
		mean_sqr = mean * mean;
		variance  = (in_sqr_final_sum / (fp)public.in_elem) - mean_sqr;
		deviation = sqrt(variance);
		denomT = sqrt((fp)(public.in_elem-1)) * deviation;

		for(col=1; col<=public.conv_cols; col++){
			j = col + public.joffset;
			jp1 = j + 1;
			if(public.in2_cols < jp1) ja1 = jp1 - public.in2_cols;
			else ja1 = 1;
			if(public.in_cols < j) ja2 = public.in_cols;
			else ja2 = j;

			for(row=1; row<=public.conv_rows; row++){
				i = row + public.ioffset;
				ip1 = i + 1;
				if(public.in2_rows < ip1) ia1 = ip1 - public.in2_rows;
				else ia1 = 1;
				if(public.in_rows < i) ia2 = public.in_rows;
				else ia2 = i;

				s = 0.0f;
				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s += p_in_mod[public.in_rows*(ja-1)+ia-1] * p_in2[public.in2_rows*(jb-1)+ib-1];
					}
				}
				p_conv[(col-1)*public.conv_rows+(row-1)] = s;
			}
		}

		for(col=0; col<public.in2_pad_cumv_cols; col++){
			for(row=0; row<public.in2_pad_cumv_rows; row++){
				if(row > (public.in2_pad_add_rows-1) &&
				   row < (public.in2_pad_add_rows+public.in2_rows) &&
				   col > (public.in2_pad_add_cols-1) &&
				   col < (public.in2_pad_add_cols+public.in2_cols)){
					ori_row = row - public.in2_pad_add_rows;
					ori_col = col - public.in2_pad_add_cols;
					p_in2_pad[col*public.in2_pad_cumv_rows+row] = p_in2[ori_col*public.in2_rows+ori_row];
				}else{
					p_in2_pad[col*public.in2_pad_cumv_rows+row] = 0.0f;
				}
			}
		}

		for(ei_new=0; ei_new<public.in2_pad_cumv_cols; ei_new++){
			pos_ori = ei_new*public.in2_pad_cumv_rows;
			sum = 0.0f;
			for(position=pos_ori; position<pos_ori+public.in2_pad_cumv_rows; position++){
				p_in2_pad[position] = p_in2_pad[position] + sum;
				sum = p_in2_pad[position];
			}
		}

		for(col=0; col<public.in2_pad_cumv_sel_cols; col++){
			for(row=0; row<public.in2_pad_cumv_sel_rows; row++){
				ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + public.in2_pad_cumv_sel_collow - 1;
				temp = p_in2_pad[ori_col*public.in2_pad_cumv_rows+ori_row];

				ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
				temp2 = p_in2_pad[ori_col*public.in2_pad_cumv_rows+ori_row];

				p_in2_sub[col*public.in2_sub_cumh_rows+row] = temp - temp2;
			}
		}

		for(ei_new=0; ei_new<public.in2_sub_cumh_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0.0f;
			for(position=pos_ori; position<pos_ori+public.in2_sub_cumh_elem; position += public.in2_sub_cumh_rows){
				p_in2_sub[position] = p_in2_sub[position] + sum;
				sum = p_in2_sub[position];
			}
		}

		for(col=0; col<public.in2_sub2_cols; col++){
			for(row=0; row<public.in2_sub2_rows; row++){
				ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + public.in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub[ori_col*public.in2_sub_cumh_rows+ori_row];

				ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub[ori_col*public.in2_sub_cumh_rows+ori_row];

				temp2 = temp - temp2;
				p_in2_sub2[col*public.in2_sub2_rows+row] = temp2;
				p_in2_sqr_sub2[col*public.in2_sub2_rows+row] = temp2 * temp2;
				p_conv[col*public.in2_sub2_rows+row] = p_conv[col*public.in2_sub2_rows+row] - temp2 * in_final_sum / (fp)public.in_elem;
			}
		}

		for(col=0; col<public.in2_pad_cumv_cols; col++){
			for(row=0; row<public.in2_pad_cumv_rows; row++){
				if(row > (public.in2_pad_add_rows-1) &&
				   row < (public.in2_pad_add_rows+public.in2_rows) &&
				   col > (public.in2_pad_add_cols-1) &&
				   col < (public.in2_pad_add_cols+public.in2_cols)){
					ori_row = row - public.in2_pad_add_rows;
					ori_col = col - public.in2_pad_add_cols;
					p_in2_pad[col*public.in2_pad_cumv_rows+row] = p_in2_sqr[ori_col*public.in2_rows+ori_row];
				}else{
					p_in2_pad[col*public.in2_pad_cumv_rows+row] = 0.0f;
				}
			}
		}

		for(ei_new=0; ei_new<public.in2_pad_cumv_cols; ei_new++){
			pos_ori = ei_new*public.in2_pad_cumv_rows;
			sum = 0.0f;
			for(position=pos_ori; position<pos_ori+public.in2_pad_cumv_rows; position++){
				p_in2_pad[position] = p_in2_pad[position] + sum;
				sum = p_in2_pad[position];
			}
		}

		for(col=0; col<public.in2_pad_cumv_sel_cols; col++){
			for(row=0; row<public.in2_pad_cumv_sel_rows; row++){
				ori_row = row + public.in2_pad_cumv_sel_rowlow - 1;
				ori_col = col + public.in2_pad_cumv_sel_collow - 1;
				temp = p_in2_pad[ori_col*public.in2_pad_cumv_rows+ori_row];

				ori_row = row + public.in2_pad_cumv_sel2_rowlow - 1;
				ori_col = col + public.in2_pad_cumv_sel2_collow - 1;
				temp2 = p_in2_pad[ori_col*public.in2_pad_cumv_rows+ori_row];

				p_in2_sub[col*public.in2_sub_cumh_rows+row] = temp - temp2;
			}
		}

		for(ei_new=0; ei_new<public.in2_sub_cumh_rows; ei_new++){
			pos_ori = ei_new;
			sum = 0.0f;
			for(position=pos_ori; position<pos_ori+public.in2_sub_cumh_elem; position += public.in2_sub_cumh_rows){
				p_in2_sub[position] = p_in2_sub[position] + sum;
				sum = p_in2_sub[position];
			}
		}

		for(col=0; col<public.conv_cols; col++){
			for(row=0; row<public.conv_rows; row++){
				ori_row = row + public.in2_sub_cumh_sel_rowlow - 1;
				ori_col = col + public.in2_sub_cumh_sel_collow - 1;
				temp = p_in2_sub[ori_col*public.in2_sub_cumh_rows+ori_row];

				ori_row = row + public.in2_sub_cumh_sel2_rowlow - 1;
				ori_col = col + public.in2_sub_cumh_sel2_collow - 1;
				temp2 = p_in2_sub[ori_col*public.in2_sub_cumh_rows+ori_row];

				temp2 = temp - temp2;
				temp2 = temp2 - (p_in2_sqr_sub2[col*public.conv_rows+row] / (fp)public.in_elem);

				if(temp2 < 0.0f) temp2 = 0.0f;
				temp2 = sqrt(temp2);
				temp2 = denomT * temp2;
				p_conv[col*public.conv_rows+row] = p_conv[col*public.conv_rows+row] / temp2;
			}
		}

		cent = public.sSize + public.tSize + 1;
		pointer = frame_no-1 + point_no*public.no_frames;
		tMask_row = cent + d_tRowLoc[pointer] - d_Row[point_no] - 1;
		tMask_col = cent + d_tColLoc[pointer] - d_Col[point_no] - 1;

		for(ei_new=0; ei_new<public.tMask_elem; ei_new++) p_tmask[ei_new] = 0.0f;
		p_tmask[tMask_col*public.tMask_rows + tMask_row] = 1.0f;

		for(col=1; col<=public.mask_conv_cols; col++){
			j = col + public.mask_conv_joffset;
			jp1 = j + 1;
			if(public.mask_cols < jp1) ja1 = jp1 - public.mask_cols;
			else ja1 = 1;
			if(public.tMask_cols < j) ja2 = public.tMask_cols;
			else ja2 = j;

			for(row=1; row<=public.mask_conv_rows; row++){
				i = row + public.mask_conv_ioffset;
				ip1 = i + 1;
				if(public.mask_rows < ip1) ia1 = ip1 - public.mask_rows;
				else ia1 = 1;
				if(public.tMask_rows < i) ia2 = public.tMask_rows;
				else ia2 = i;

				s = 0.0f;
				for(ja=ja1; ja<=ja2; ja++){
					jb = jp1 - ja;
					for(ia=ia1; ia<=ia2; ia++){
						ib = ip1 - ia;
						s += p_tmask[public.tMask_rows*(ja-1)+ia-1] * 1.0f;
					}
				}
				p_mask_conv[(col-1)*public.conv_rows+(row-1)] = p_conv[(col-1)*public.conv_rows+(row-1)] * s;
			}
		}

		fin_max_val = 0.0f;
		fin_max_coo = 0;
		for(i=0; i<public.mask_conv_elem; i++){
			if(p_mask_conv[i] > fin_max_val){
				fin_max_val = p_mask_conv[i];
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo+1) % public.mask_conv_rows - 1;
		largest_col = (fin_max_coo+1) / public.mask_conv_rows;
		if((fin_max_coo+1) % public.mask_conv_rows == 0){
			largest_row = public.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - public.in_rows - (public.sSize - public.tSize);
		offset_col = largest_col - public.in_cols - (public.sSize - public.tSize);
		pointer = point_no*public.no_frames + frame_no;
		d_tRowLoc[pointer] = d_Row[point_no] + offset_row;
		d_tColLoc[pointer] = d_Col[point_no] + offset_col;
	}

	if(frame_no != 0 && (frame_no % 10) == 0){
		loc_pointer = point_no*public.no_frames + frame_no;
		d_Row[point_no] = d_tRowLoc[loc_pointer];
		d_Col[point_no] = d_tColLoc[loc_pointer];

		in_ptr = d_T + in_pointer;
		for(col=0; col<public.in_cols; col++){
			for(row=0; row<public.in_rows; row++){
				ori_row = d_Row[point_no] - 25 + row - 1;
				ori_col = d_Col[point_no] - 25 + col - 1;
				ori_pointer = ori_col*public.frame_rows + ori_row;
				in_ptr[col*public.in_rows+row] = public.alpha*in_ptr[col*public.in_rows+row] + (1.0f-public.alpha)*d_frame[ori_pointer];
			}
		}
	}
}

