#endif

__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      const int cols,
                      const int rows,
                      const int borderCols,
                      const int borderRows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    const int tx = get_local_id(0);
    const int ty = get_local_id(1);
    const int bx = get_group_id(0);
    const int by = get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - iteration * 2;
    const int small_block_rows = BLOCK_SIZE - iteration * 2;

    const int blkX = bx * small_block_cols - borderCols;
    const int blkY = by * small_block_rows - borderRows;

    const int xidx = blkX + tx;
    const int yidx = blkY + ty;

    const int lidx = ty * BLOCK_SIZE + tx;

    __local float temp_tile[BLOCK_SIZE * BLOCK_SIZE];
    __local float power_tile[BLOCK_SIZE * BLOCK_SIZE];

    const int in_range = (xidx >= 0 && xidx < cols && yidx >= 0 && yidx < rows);
    if (in_range) {
        const int gidx = yidx * cols + xidx;
        temp_tile[lidx] = temp_src[gidx];
        power_tile[lidx] = power[gidx];
    } else {
        temp_tile[lidx] = 0.0f;
        power_tile[lidx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    const float step_div_Cap = step / Cap;
    const float invRx = 1.0f / Rx;
    const float invRy = 1.0f / Ry;
    const float invRz = 1.0f / Rz;

    for (int i = 0; i < iteration; i++) {
        float new_temp = temp_tile[lidx];

        const int compute_inner =
            (tx >= (i + 1)) && (tx < (BLOCK_SIZE - i - 1)) &&
            (ty >= (i + 1)) && (ty < (BLOCK_SIZE - i - 1)) &&
            in_range;

        if (compute_inner) {
            const float center = temp_tile[lidx];

            const float north = (yidx == 0)        ? center : temp_tile[(ty - 1) * BLOCK_SIZE + tx];
            const float south = (yidx == rows - 1) ? center : temp_tile[(ty + 1) * BLOCK_SIZE + tx];
            const float west  = (xidx == 0)        ? center : temp_tile[ty * BLOCK_SIZE + (tx - 1)];
            const float east  = (xidx == cols - 1) ? center : temp_tile[ty * BLOCK_SIZE + (tx + 1)];

            const float delta = step_div_Cap *
                                (power_tile[lidx] +
                                 (east + west - 2.0f * center) * invRx +
                                 (south + north - 2.0f * center) * invRy +
                                 (80.0f - center) * invRz);

            new_temp = center + delta;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (compute_inner) {
            temp_tile[lidx] = new_temp;
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    const int write_back =
        (tx >= iteration) && (tx < (BLOCK_SIZE - iteration)) &&
        (ty >= iteration) && (ty < (BLOCK_SIZE - iteration)) &&
        in_range;

    if (write_back) {
        temp_dst[yidx * cols + xidx] = temp_tile[lidx];
    }
}

__kernel void hotspot(int iteration,
                      __global const float *power,
                      __global float *temp_src,
                      __global float *temp_dst,
                      int col,
                      int row,
                      int borderCols,
                      int borderRows,
                      float Cap,
                      float Rx,
                      float Ry,
                      float Rz,
                      float step)
{
    (void)borderCols;
    (void)borderRows;

    if (get_global_id(0) != 0 || get_global_id(1) != 0) {
        return;
    }

    const float amb_temp = 80.0f;
    const float step_local = step / 1000.0f;

    const float Rx_1 = 1.0f / Rx;
    const float Ry_1 = 1.0f / Ry;
    const float Rz_1 = 1.0f / Rz;
    const float Cap_1 = step_local / Cap;

    for (int it = 0; it < iteration; ++it) {
        __global float *src = (it & 1) ? temp_dst : temp_src;
        __global float *dst = (it & 1) ? temp_src : temp_dst;

        for (int r = 0; r < row; ++r) {
            int rcol = r * col;
            for (int c = 0; c < col; ++c) {
                int idx = rcol + c;
                float delta;

                if ((r == 0) && (c == 0)) {
                    delta = (Cap_1) * (power[0] +
                                       (src[1] - src[0]) * Rx_1 +
                                       (src[col] - src[0]) * Ry_1 +
                                       (amb_temp - src[0]) * Rz_1);
                } else if ((r == 0) && (c == col - 1)) {
                    delta = (Cap_1) * (power[c] +
                                       (src[c - 1] - src[c]) * Rx_1 +
                                       (src[c + col] - src[c]) * Ry_1 +
                                       (amb_temp - src[c]) * Rz_1);
                } else if ((r == row - 1) && (c == col - 1)) {
                    delta = (Cap_1) * (power[idx] +
                                       (src[idx - 1] - src[idx]) * Rx_1 +
                                       (src[(r - 1) * col + c] - src[idx]) * Ry_1 +
                                       (amb_temp - src[idx]) * Rz_1);
                } else if ((r == row - 1) && (c == 0)) {
                    delta = (Cap_1) * (power[rcol] +
                                       (src[rcol + 1] - src[rcol]) * Rx_1 +
                                       (src[(r - 1) * col] - src[rcol]) * Ry_1 +
                                       (amb_temp - src[rcol]) * Rz_1);
                } else if (r == 0) {
                    delta = (Cap_1) * (power[c] +
                                       (src[c + 1] + src[c - 1] - 2.0f * src[c]) * Rx_1 +
                                       (src[col + c] - src[c]) * Ry_1 +
                                       (amb_temp - src[c]) * Rz_1);
                } else if (c == col - 1) {
                    delta = (Cap_1) * (power[idx] +
                                       (src[(r + 1) * col + c] + src[(r - 1) * col + c] - 2.0f * src[idx]) * Ry_1 +
                                       (src[idx - 1] - src[idx]) * Rx_1 +
                                       (amb_temp - src[idx]) * Rz_1);
                } else if (r == row - 1) {
                    delta = (Cap_1) * (power[idx] +
                                       (src[idx + 1] + src[idx - 1] - 2.0f * src[idx]) * Rx_1 +
                                       (src[(r - 1) * col + c] - src[idx]) * Ry_1 +
                                       (amb_temp - src[idx]) * Rz_1);
                } else if (c == 0) {
                    delta = (Cap_1) * (power[rcol] +
                                       (src[(r + 1) * col] + src[(r - 1) * col] - 2.0f * src[rcol]) * Ry_1 +
                                       (src[rcol + 1] - src[rcol]) * Rx_1 +
                                       (amb_temp - src[rcol]) * Rz_1);
                } else {
                    delta = (Cap_1) * (power[idx] +
                                       (src[(r + 1) * col + c] + src[(r - 1) * col + c] - 2.0f * src[idx]) * Ry_1 +
                                       (src[idx + 1] + src[idx - 1] - 2.0f * src[idx]) * Rx_1 +
                                       (amb_temp - src[idx]) * Rz_1);
                }

                dst[idx] = src[idx] + delta;
            }
        }
    }

    if ((iteration & 1) == 0) {
        int size = row * col;
        for (int i = 0; i < size; ++i) {
            temp_dst[i] = temp_src[i];
        }
    }
}

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))

__kernel void hotspot(const int iteration,
                      __global const float *power,
                      __global const float *temp_src,
                      __global float *temp_dst,
                      const int col,
                      const int row,
                      const int border_cols,
                      const int border_rows,
                      const float Cap,
                      const float Rx,
                      const float Ry,
                      const float Rz,
                      const float step)
{
    const int tx = (int)get_local_id(0);
    const int ty = (int)get_local_id(1);
    const int bx = (int)get_group_id(0);
    const int by = (int)get_group_id(1);

    const int small_block_cols = BLOCK_SIZE - (border_cols << 1);
    const int small_block_rows = BLOCK_SIZE - (border_rows << 1);

    const int blkX = small_block_cols * bx - border_cols;
    const int blkY = small_block_rows * by - border_rows;

    const int xidx = blkX + tx;
    const int yidx = blkY + ty;

    const int index = yidx * col + xidx;

    const int validXmin = (blkX < 0) ? -blkX : 0;
    const int validYmin = (blkY < 0) ? -blkY : 0;
    const int validXmax = ((blkX + BLOCK_SIZE) > col) ? (col - blkX) : BLOCK_SIZE;
    const int validYmax = ((blkY + BLOCK_SIZE) > row) ? (row - blkY) : BLOCK_SIZE;

    const float stepDivCap = step / Cap;
    const float ce = stepDivCap / Rx;
    const float cw = ce;
    const float cn = stepDivCap / Ry;
    const float cs = cn;
    const float ct = stepDivCap / Rz;

    __local float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    if (IN_RANGE(tx, validXmin, validXmax - 1) && IN_RANGE(ty, validYmin, validYmax - 1)) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    } else {
        temp_on_cuda[ty][tx] = 0.0f;
        power_on_cuda[ty][tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    for (int i = 0; i < iteration; i++) {
        int computed = 0;

        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
            IN_RANGE(tx, validXmin + i, validXmax - i - 1) &&
            IN_RANGE(ty, validYmin + i, validYmax - i - 1)) {

            const float center = temp_on_cuda[ty][tx];
            const float north = (yidx == 0)      ? center : temp_on_cuda[ty - 1][tx];
            const float south = (yidx == row - 1)? center : temp_on_cuda[ty + 1][tx];
            const float west  = (xidx == 0)      ? center : temp_on_cuda[ty][tx - 1];
            const float east  = (xidx == col - 1)? center : temp_on_cuda[ty][tx + 1];

            const float delta =
                (power_on_cuda[ty][tx] +
                 (south + north - 2.0f * center) * cs +
                 (east + west - 2.0f * center) * ce +
                 (80.0f - center) * ct);

            temp_t[ty][tx] = center + delta;
            computed = 1;
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (computed) {
            temp_on_cuda[ty][tx] = temp_t[ty][tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (IN_RANGE(tx, border_cols, BLOCK_SIZE - border_cols - 1) &&
        IN_RANGE(ty, border_rows, BLOCK_SIZE - border_rows - 1) &&
        IN_RANGE(tx, validXmin, validXmax - 1) &&
        IN_RANGE(ty, validYmin, validYmax - 1)) {
        temp_dst[index] = temp_on_cuda[ty][tx];
    }
}

