__kernel void kernel_gpu_opencl(fp timeinst,
                                 __global fp *initvalu,
                                 __global fp *finavalu,
                                 __global fp *parameter,
                                 __global fp *com){

    int tid = (int)get_global_id(0);
    if (tid > 3) return;

    if (tid == 0){
        ecc(timeinst, initvalu, 0, parameter, 0, finavalu);
    }
    else if (tid == 1){
        fp CaDyad = initvalu[35]*1e3f;
        com[0] = cam(timeinst, initvalu, 46, parameter, 1, finavalu, CaDyad);
    }
    else if (tid == 2){
        fp CaSL = initvalu[36]*1e3f;
        com[1] = cam(timeinst, initvalu, 61, parameter, 6, finavalu, CaSL);
    }
    else if (tid == 3){
        fp CaCyt = initvalu[37]*1e3f;
        com[2] = cam(timeinst, initvalu, 76, parameter, 11, finavalu, CaCyt);
    }
}

