    fp rcnCKt2b2;
    fp rcnCKai;

    fp dCaM;
    fp dCa2CaM;
    fp dCa4CaM;
    fp dCaMB;
    fp dCa2CaMB;
    fp dCa4CaMB;

    fp dPb2;
    fp dPb;
    fp dPt;
    fp dPt2;
    fp dPa;

    fp dCa4CaN;
    fp dCaMCa4CaN;
    fp dCa2CaMCa4CaN;
    fp dCa4CaMCa4CaN;

    offset_1  = initvalu_offset;
    offset_2  = initvalu_offset+1;
    offset_3  = initvalu_offset+2;
    offset_4  = initvalu_offset+3;
    offset_5  = initvalu_offset+4;
