typedef struct {
    float weight;
    long  assign;
    float cost;
} Point_Struct;

inline void pgain_body(__global Point_Struct *p,
                       __global const float *coord,
                       __global float *work_mem,
                       __global const int *center_table,
                       __global char *switch_membership,
                       __local float *x_coord,
                       const int num,
                       const int dim,
                       const long x,
                       const int K) {
    const int lid = (int)get_local_id(0);
    const int lsize = (int)get_local_size(0);

    for (int d = lid; d < dim; d += lsize) {
        x_coord[d] = coord[d * num + (int)x];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    const int i = (int)get_global_id(0);
    if (i >= num) return;

    float x_cost = 0.0f;
    for (int d = 0; d < dim; d++) {
        float diff = coord[d * num + i] - x_coord[d];
        x_cost += diff * diff;
    }
    x_cost *= p[i].weight;

    const float current_cost = p[i].cost;
    const int base = i * (K + 1);

    if (x_cost < current_cost) {
        switch_membership[i] = '1';
        work_mem[base + K] = x_cost - current_cost;
    } else {
        const int assign = (int)p[i].assign;
        const int cidx = center_table[assign];
        work_mem[base + cidx] = current_cost - x_cost;
    }
}

